// frontend/src/pages/JS JobMatcher.js
import React, { useState, useEffect } from 'react';
import axios from 'axios';
// import '../CSS App.css';

const JobMatcher = () => {
  const [jobDescription, setJobDescription] = useState('');
  const [resumeText, setResumeText] = useState('');
  const [matchResult, setMatchResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [aiStatus, setAiStatus] = useState('checking');
  const [resumeCategory, setResumeCategory] = useState(null);

  const token = localStorage.getItem('token');
  const BACKEND_URL = 'http://localhost:5000';
  const AI_API_URL = 'http://localhost:5001';

  // Check AI Service Status
  useEffect(() => {
    checkAIStatus();
    loadUserResume();
  }, []);

  const checkAIStatus = async () => {
    try {
      const response = await axios.get(`${AI_API_URL}/health`);
      setAiStatus(response.data.status === 'AI Service Running' ? 'online' : 'offline');
    } catch (error) {
      setAiStatus('offline');
    }
  };

  const loadUserResume = async () => {
    try {
      // Fetch user's latest resume from backend
      const response = await axios.get(`${BACKEND_URL}/api/applications`, {
        headers: { 'x-auth-token': token }
      });
      if (response.data && response.data.length > 0) {
        // Use the latest application's resume text
        const latestResume = response.data[0].resumeText || '';
        setResumeText(latestResume);
        if (latestResume) {
          predictResumeCategory(latestResume);
        }
      }
    } catch (error) {
      console.error('Error loading resume:', error);
    }
  };

  const predictResumeCategory = async (text) => {
    try {
      const response = await axios.post(`${AI_API_URL}/predict/category`, {
        resume_text: text
      });
      setResumeCategory(response.data.predicted_category);
    } catch (error) {
      console.error('Category prediction failed:', error);
    }
  };

  const analyzeMatch = async () => {
    if (!jobDescription) {
      alert('Please paste a job description');
      return;
    }

    if (!resumeText) {
      alert('Please upload your resume first in Dashboard');
      return;
    }

    setLoading(true);
    try {
      const response = await axios.post(`${AI_API_URL}/predict/match`, {
        resume_text: resumeText,
        job_description: jobDescription,
        job_title: 'Job Position'
      });
      setMatchResult(response.data);
    } catch (error) {
      console.error('Match analysis failed:', error);
      alert('AI Service error. Make sure Python API is running on port 5001');
    }
    setLoading(false);
  };

  const getMatchColor = (score) => {
    if (score >= 70) return '#28a745';
    if (score >= 50) return '#17a2b8';
    if (score >= 30) return '#ffc107';
    return '#dc3545';
  };

  const getMatchText = (score) => {
    if (score >= 70) return 'Excellent Match! 🎯';
    if (score >= 50) return 'Good Match 👍';
    if (score >= 30) return 'Fair Match 📝';
    return 'Poor Match ❌';
  };

  return (
    <div className="job-matcher-container">
      <div className="container">
        <h1>🎯 Job Match Analyzer</h1>

        {/* AI Status Indicator */}
        <div className={`ai-status-badge ${aiStatus}`}>
          {aiStatus === 'online' ? (
            <span>✅ AI Service Connected</span>
          ) : (
            <span>⚠️ AI Service Offline - Run python predict_api.py</span>
          )}
        </div>

        {/* Resume Category Display */}
        {resumeCategory && (
          <div className="resume-category-card">
            <strong>📄 Your Resume Category:</strong> 
            <span className="category-tag">{resumeCategory}</span>
            <p className="hint">AI predicts you're best suited for {resumeCategory} roles</p>
          </div>
        )}

        <div className="matcher-layout">
          {/* Left Column - Input */}
          <div className="input-section">
            <div className="form-group">
              <label>📝 Job Description</label>
              <textarea
                rows="15"
                value={jobDescription}
                onChange={(e) => setJobDescription(e.target.value)}
                placeholder="Paste the job description here...
                
Example:
Looking for a Python Developer with 3+ years experience in Django, React, and SQL. Must have strong communication skills and experience with AWS."
                className="job-description-input"
              />
            </div>

            <button 
              onClick={analyzeMatch}
              disabled={loading || aiStatus === 'offline'}
              className="analyze-btn"
            >
              {loading ? '🤖 Analyzing...' : '🔍 Analyze Match'}
            </button>

            {!resumeText && (
              <p className="warning">
                ⚠️ No resume found. Please upload your resume in Dashboard first.
              </p>
            )}
          </div>

          {/* Right Column - Results */}
          <div className="results-section">
            <h3>📊 Match Results</h3>
            
            {matchResult ? (
              <div className="match-card">
                <div className="match-score-circle" style={{ borderColor: getMatchColor(matchResult.match_score) }}>
                  <span className="score-number">{matchResult.match_score}%</span>
                  <span className="score-label">Match</span>
                </div>

                <div className="match-level" style={{ color: getMatchColor(matchResult.match_score) }}>
                  {getMatchText(matchResult.match_score)}
                </div>

                <div className="match-details">
                  <div className="detail-item">
                    <span className="detail-label">🎯 Matching Skills:</span>
                    <span className="detail-value">{matchResult.matching_skills} / {matchResult.total_job_skills}</span>
                  </div>

                  <div className="detail-item">
                    <span className="detail-label">📋 Your Top Skills:</span>
                    <div className="skill-tags">
                      {(matchResult.resume_skills || []).map((skill, i) => (
                        <span key={i} className="skill-tag resume-skill">{skill}</span>
                      ))}
                      {(!matchResult.resume_skills || matchResult.resume_skills.length === 0) && (
                        <span className="no-skills">No skills detected</span>
                      )}
                    </div>
                  </div>

                  <div className="detail-item">
                    <span className="detail-label">💼 Job Required Skills:</span>
                    <div className="skill-tags">
                      {(matchResult.job_skills || []).map((skill, i) => (
                        <span key={i} className="skill-tag job-skill">{skill}</span>
                      ))}
                      {(!matchResult.job_skills || matchResult.job_skills.length === 0) && (
                        <span className="no-skills">No specific skills detected</span>
                      )}
                    </div>
                  </div>
                </div>

                <div className="recommendation">
                  {matchResult.match_score >= 70 && (
                    <p>✅ You're a great fit! Prepare for an interview.</p>
                  )}
                  {matchResult.match_score >= 50 && matchResult.match_score < 70 && (
                    <p>📈 Good match! Highlight your matching skills in your application.</p>
                  )}
                  {matchResult.match_score >= 30 && matchResult.match_score < 50 && (
                    <p>📚 Fair match. Consider upskilling in missing areas.</p>
                  )}
                  {matchResult.match_score < 30 && (
                    <p>🔄 Low match. Look for roles that better align with your skills.</p>
                  )}
                </div>
              </div>
            ) : (
              <div className="no-results-placeholder">
                <p>📌 Paste a job description and click "Analyze Match"</p>
                <p className="hint">AI will compare your resume with the job and show match score</p>
              </div>
            )}
          </div>
        </div>
      </div>

      <style jsx>{`
        .job-matcher-container {
          padding: 20px;
          max-width: 1400px;
          margin: 0 auto;
        }
        h1 {
          color: #333;
          margin-bottom: 20px;
        }
        .ai-status-badge {
          padding: 10px;
          border-radius: 5px;
          margin-bottom: 20px;
        }
        .ai-status-badge.online {
          background: #d4edda;
          color: #155724;
        }
        .ai-status-badge.offline {
          background: #f8d7da;
          color: #721c24;
        }
        .resume-category-card {
          background: #e8f4f8;
          padding: 15px;
          border-radius: 10px;
          margin-bottom: 20px;
        }
        .category-tag {
          background: #007bff;
          color: white;
          padding: 5px 15px;
          border-radius: 20px;
          margin-left: 10px;
          display: inline-block;
        }
        .matcher-layout {
          display: grid;
          grid-template-columns: 1fr 1fr;
          gap: 30px;
        }
        .job-description-input {
          width: 100%;
          padding: 10px;
          border: 1px solid #ddd;
          border-radius: 5px;
          font-family: monospace;
          font-size: 14px;
        }
        .analyze-btn {
          background: #007bff;
          color: white;
          border: none;
          padding: 12px 30px;
          border-radius: 5px;
          cursor: pointer;
          font-size: 16px;
          margin-top: 15px;
        }
        .analyze-btn:disabled {
          background: #6c757d;
          cursor: not-allowed;
        }
        .match-card {
          background: white;
          border: 1px solid #ddd;
          border-radius: 10px;
          padding: 20px;
          text-align: center;
        }
        .match-score-circle {
          width: 150px;
          height: 150px;
          border-radius: 50%;
          border: 8px solid;
          display: flex;
          flex-direction: column;
          align-items: center;
          justify-content: center;
          margin: 0 auto 20px;
        }
        .score-number {
          font-size: 48px;
          font-weight: bold;
        }
        .score-label {
          font-size: 14px;
        }
        .match-level {
          font-size: 24px;
          font-weight: bold;
          margin-bottom: 20px;
        }
        .detail-item {
          text-align: left;
          margin-bottom: 15px;
        }
        .detail-label {
          font-weight: bold;
          display: block;
          margin-bottom: 8px;
        }
        .skill-tags {
          display: flex;
          flex-wrap: wrap;
          gap: 8px;
        }
        .skill-tag {
          padding: 5px 12px;
          border-radius: 20px;
          font-size: 12px;
        }
        .resume-skill {
          background: #d4edda;
          color: #155724;
        }
        .job-skill {
          background: #fff3cd;
          color: #856404;
        }
        .warning {
          color: #dc3545;
          margin-top: 15px;
        }
        .no-results-placeholder {
          text-align: center;
          padding: 50px;
          background: #f8f9fa;
          border-radius: 10px;
        }
        .hint {
          color: #6c757d;
          font-size: 12px;
          margin-top: 5px;
        }
        @media (max-width: 800px) {
          .matcher-layout {
            grid-template-columns: 1fr;
          }
        }
      `}</style>
    </div>
  );
};

export default JobMatcher;
